  "name": "ledger-server",
  "version": "1.0.0",
  "description": "Ledger backend — Node/Express + SQLite",
  "main": "src/index.js",
  "scripts": {
    "start": "node src/index.js",
    "dev": "node --watch src/index.js"
  },
  "dependencies": {
    "better-sqlite3": "^9.4.3",
    "cors": "^2.8.5",
    "dotenv": "^16.4.5",
    "express": "^4.19.2",
    "uuid": "^9.0.1"
  }
}

{
  "name": "ledger-client",
  "version": "1.0.0",
  "description": "Ledger frontend — React + Tiptap",
  "type": "module",
  "scripts": {
    "dev": "vite",
    "build": "vite build",
    "preview": "vite preview"
  },
  "dependencies": {
    "@tiptap/core": "^2.4.0",
    "@tiptap/extension-document": "^2.4.0",
    "@tiptap/extension-paragraph": "^2.4.0",
    "@tiptap/extension-text": "^2.4.0",
    "@tiptap/extension-history": "^2.4.0",
    "@tiptap/react": "^2.4.0",
    "react": "^18.3.1",
    "react-dom": "^18.3.1"
  },
  "devDependencies": {
    "@vitejs/plugin-react": "^4.3.1",
    "vite": "^5.3.1"
  }
}

const Database = require('better-sqlite3');
const path = require('path');
const { v4: uuidv4 } = require('uuid');

const DB_PATH = path.join(__dirname, '..', 'ledger.db');

// ---------------------------------------------------------------------------
// Schema
// ---------------------------------------------------------------------------
const SCHEMA = `
  PRAGMA journal_mode = WAL;
  PRAGMA foreign_keys = ON;

  CREATE TABLE IF NOT EXISTS documents (
    id          TEXT PRIMARY KEY,
    title       TEXT NOT NULL,
    root_content TEXT NOT NULL DEFAULT '',
    created_at  TEXT NOT NULL DEFAULT (datetime('now'))
  );

  CREATE TABLE IF NOT EXISTS forks (
    id               TEXT PRIMARY KEY,
    document_id      TEXT NOT NULL REFERENCES documents(id),
    parent_fork_id   TEXT REFERENCES forks(id),
    anchor_start     INTEGER NOT NULL,
    anchor_end       INTEGER NOT NULL,
    original_snippet TEXT NOT NULL,
    -- Hard cap: 8 000 chars prevents unbounded AI output from corrupting resolution
    branch_content   TEXT NOT NULL CHECK(length(branch_content) <= 8000),
    why              TEXT CHECK(why IS NULL OR length(why) <= 2000),
    status           TEXT NOT NULL CHECK(status IN ('proposed','resolved','failed'))
                       DEFAULT 'proposed',
    is_active        INTEGER NOT NULL DEFAULT 0 CHECK(is_active IN (0,1)),
    created_at       TEXT NOT NULL DEFAULT (datetime('now')),
    updated_at       TEXT NOT NULL DEFAULT (datetime('now'))
  );

  -- At most one proposed fork per document (concurrency lock)
  CREATE UNIQUE INDEX IF NOT EXISTS uq_one_proposed_per_doc
    ON forks(document_id)
    WHERE status = 'proposed';

  -- At most one active fork per (document, anchor point)
  CREATE UNIQUE INDEX IF NOT EXISTS uq_one_active_per_anchor
    ON forks(document_id, anchor_start, anchor_end)
    WHERE is_active = 1;
`;

// ---------------------------------------------------------------------------
// Seed data
// ---------------------------------------------------------------------------
const SEED_DOCUMENT_ID = 'doc_hardcoded_001';
const SEED_TITLE = 'My First Document';
const SEED_CONTENT = `The morning light filtered through the half-drawn blinds, casting long amber stripes across the wooden floor. She sat at her desk with a cup of tea that had long gone cold, staring at the blank page in front of her.

There was a story she needed to tell — one she had been carrying for years, turning it over in her mind like a smooth stone worn by river water. But every time she reached for the right first word, it slipped away like a fish darting into deep water.

She picked up her pen anyway. The first sentence didn't have to be perfect. It just had to exist.`;

// ---------------------------------------------------------------------------
// Open / initialise DB
// ---------------------------------------------------------------------------
let db;

function getDb() {
  if (!db) {
    db = new Database(DB_PATH);
    db.exec(SCHEMA);
    seedDocument(db);
  }
  return db;
}

function seedDocument(database) {
  const insert = database.prepare(`
    INSERT OR IGNORE INTO documents (id, title, root_content)
    VALUES (?, ?, ?)
  `);
  insert.run(SEED_DOCUMENT_ID, SEED_TITLE, SEED_CONTENT);
}

module.exports = { getDb, SEED_DOCUMENT_ID };

'use strict';

require('dotenv').config({ path: require('path').join(__dirname, '..', '..', '.env') });

const express = require('express');
const cors = require('cors');
const { getDb } = require('./db');
const { resolveDocument } = require('./resolve');

const app = express();
app.use(express.json());

// ---------------------------------------------------------------------------
// CORS
// ---------------------------------------------------------------------------
const corsOrigin = process.env.CORS_ORIGIN;
if (corsOrigin) {
  app.use(cors({ origin: corsOrigin, credentials: true }));
}
// If CORS_ORIGIN is unset, assume frontend is served from the same origin
// (e.g. production static serve) — no CORS header needed.

// ---------------------------------------------------------------------------
// Routes
// ---------------------------------------------------------------------------

/**
 * GET /document/:id/resolved
 * Returns the segment array for the resolved document.
 */
app.get('/document/:id/resolved', (req, res) => {
  const segments = resolveDocument(req.params.id);
  if (!segments) {
    return res.status(404).json({ error: 'Document not found' });
  }
  res.json({ segments });
});

/**
 * GET /document/:id
 * Returns the raw document row (title, root_content, created_at).
 */
app.get('/document/:id', (req, res) => {
  const db = getDb();
  const doc = db.prepare('SELECT id, title, root_content, created_at FROM documents WHERE id = ?').get(req.params.id);
  if (!doc) return res.status(404).json({ error: 'Document not found' });
  res.json(doc);
});

/**
 * PATCH /document/:id/content
 * Autosave: update root_content.
 * Body: { content: string }
 *
 * P1 only — in P3 this route is replaced by PATCH /document/:id/edit
 * which handles in-segment edits and appends with offset tracking.
 */
app.patch('/document/:id/content', (req, res) => {
  const { content } = req.body;
  if (typeof content !== 'string') {
    return res.status(400).json({ error: 'content must be a string' });
  }
  const db = getDb();
  const result = db
    .prepare('UPDATE documents SET root_content = ? WHERE id = ?')
    .run(content, req.params.id);
  if (result.changes === 0) {
    return res.status(404).json({ error: 'Document not found' });
  }
  res.json({ ok: true });
});

// ---------------------------------------------------------------------------
// Start
// ---------------------------------------------------------------------------
const PORT = process.env.PORT || 3001;
app.listen(PORT, () => {
  // Eagerly initialise the DB + seed on startup
  getDb();
  console.log(`Ledger server running on http://localhost:${PORT}`);
});

const { getDb } = require('./db');

/**
 * Resolve the document into a flat segment array.
 *
 * For P1 (no forks), returns a single root segment:
 *   [{ text, fork_id: null, start: 0, end: text.length }]
 *
 * The algorithm is written for the full recursive case so P2/P3 can extend
 * it without restructuring.
 *
 * @param {string} documentId
 * @returns {{ text: string, fork_id: string|null, start: number, end: number }[]}
 */
function resolveDocument(documentId) {
  const db = getDb();

  const doc = db.prepare('SELECT root_content FROM documents WHERE id = ?').get(documentId);
  if (!doc) return null;

  // Fetch all forks for this document up front; build a lookup by parent_fork_id
  const allForks = db
    .prepare(
      `SELECT id, parent_fork_id, anchor_start, anchor_end, branch_content, is_active, status
       FROM forks
       WHERE document_id = ?
       ORDER BY created_at ASC`
    )
    .all(documentId);

  // children[parentId] = list of fork rows (null key = root's children)
  const children = {};
  for (const fork of allForks) {
    const key = fork.parent_fork_id ?? '__root__';
    if (!children[key]) children[key] = [];
    children[key].push(fork);
  }

  // Recursive descent; returns segment array with offsets relative to
  // the *start* offset passed in (position within the final resolved document).
  function descend(text, forkId, startOffset) {
    const key = forkId ?? '__root__';
    const forkChildren = children[key] || [];

    // Only the single active+resolved child at each anchor point participates.
    // We sort by anchor_start so we process substitutions left-to-right.
    const activeForks = forkChildren
      .filter((f) => f.is_active === 1 && f.status === 'resolved')
      .sort((a, b) => a.anchor_start - b.anchor_start);

    if (activeForks.length === 0) {
      // Leaf: return the text as a single segment
      return [{ text, fork_id: forkId, start: startOffset, end: startOffset + text.length }];
    }

    const segments = [];
    let cursor = 0; // position within `text`
    let outputOffset = startOffset;

    for (const fork of activeForks) {
      // Text before this fork's anchor range (belongs to current forkId node)
      if (fork.anchor_start > cursor) {
        const before = text.slice(cursor, fork.anchor_start);
        segments.push({ text: before, fork_id: forkId, start: outputOffset, end: outputOffset + before.length });
        outputOffset += before.length;
      }

      // Recurse into fork's branch_content (fork owns this segment)
      const childSegments = descend(fork.branch_content, fork.id, outputOffset);
      segments.push(...childSegments);
      outputOffset += fork.branch_content.length; // approximate — recursive descent tracks its own offsets

      cursor = fork.anchor_end;
    }

    // Trailing text after all forks
    if (cursor < text.length) {
      const after = text.slice(cursor);
      segments.push({ text: after, fork_id: forkId, start: outputOffset, end: outputOffset + after.length });
    }

    return segments;
  }

  return descend(doc.root_content, null, 0);
}

module.exports = { resolveDocument };

