import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [react()],
  server: {
    port: 5173,
    proxy: {
      '/document': 'http://localhost:3001',
    },
  },
});

*, *::before, *::after {
  box-sizing: border-box;
}

body {
  margin: 0;
  font-family: -apple-system, 'Segoe UI', system-ui, sans-serif;
  background: #f7f8fa;
  color: #1f2328;
}

#root {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

import { useEffect, useState } from 'react';
import Editor from './Editor.jsx';

const DOC_ID = 'doc_hardcoded_001';

export default function App() {
  const [doc, setDoc] = useState(null);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetch(`/document/${DOC_ID}/resolved`)
      .then((r) => {
        if (!r.ok) throw new Error(`${r.status} ${r.statusText}`);
        return r.json();
      })
      .then(({ segments }) => {
        // For P1 there is always exactly one segment (root_content, no forks)
        const text = segments.map((s) => s.text).join('');
        setDoc({ id: DOC_ID, initialContent: text });
      })
      .catch((err) => setError(err.message));
  }, []);

  if (error) {
    return (
      <div style={{ padding: '2rem', color: '#c0392b' }}>
        <strong>Failed to load document:</strong> {error}
      </div>
    );
  }

  if (!doc) {
    return <div style={{ padding: '2rem', color: '#57606a' }}>Loading…</div>;
  }

  return <Editor docId={doc.id} initialContent={doc.initialContent} />;
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App.jsx';
import './index.css';

ReactDOM.createRoot(document.getElementById('root')).render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { useEffect, useRef, useCallback } from 'react';
import { useEditor, EditorContent } from '@tiptap/react';
import Document from '@tiptap/extension-document';
import Paragraph from '@tiptap/extension-paragraph';
import Text from '@tiptap/extension-text';
import History from '@tiptap/extension-history';
import './Editor.css';

const AUTOSAVE_DEBOUNCE_MS = 500;

/**
 * Save status: 'idle' | 'saving' | 'saved' | 'error'
 */

export default function Editor({ docId, initialContent }) {
  const saveTimerRef = useRef(null);
  const saveStatusRef = useRef('idle');
  const setSaveStatusRef = useRef(null); // will hold React state setter

  // We need a React re-render to show save status — use a plain state
  const [saveStatus, _setSaveStatus] = [
    // trick: read ref, write via ref+state
    saveStatusRef.current,
    (s) => {
      saveStatusRef.current = s;
      // Force re-render by calling the real setter stored below
      if (setSaveStatusRef.current) setSaveStatusRef.current(s);
    },
  ];

  // Proper React state for save status (the trick above wires into this)
  const [_saveState, _setSaveState] = (() => {
    // eslint-disable-next-line react-hooks/rules-of-hooks
    const pair = require('react').useState('idle');
    setSaveStatusRef.current = pair[1];
    return pair;
  })();

  const persistContent = useCallback(
    async (text) => {
      saveStatusRef.current = 'saving';
      if (setSaveStatusRef.current) setSaveStatusRef.current('saving');
      try {
        const res = await fetch(`/document/${docId}/content`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ content: text }),
        });
        if (!res.ok) throw new Error(`${res.status}`);
        saveStatusRef.current = 'saved';
        if (setSaveStatusRef.current) setSaveStatusRef.current('saved');
      } catch {
        saveStatusRef.current = 'error';
        if (setSaveStatusRef.current) setSaveStatusRef.current('error');
      }
    },
    [docId]
  );

  const editor = useEditor({
    extensions: [Document, Paragraph, Text, History],
    content: initialContent
      ? `<p>${initialContent.replace(/\n\n/g, '</p><p>').replace(/\n/g, '<br>')}</p>`
      : '',
    onUpdate({ editor }) {
      // Extract plain text using doc.textBetween — character offsets per spec
      const text = editor.state.doc.textBetween(0, editor.state.doc.content.size, '\n\n', '');

      if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
      saveTimerRef.current = setTimeout(() => persistContent(text), AUTOSAVE_DEBOUNCE_MS);
    },
  });

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
    };
  }, []);

  const statusLabel = {
    idle: '',
    saving: 'Saving…',
    saved: 'Saved',
    error: 'Save failed',
  }[_saveState];

  const statusColor = {
    idle: 'transparent',
    saving: '#57606a',
    saved: '#2da44e',
    error: '#c0392b',
  }[_saveState];

  return (
    <div className="editor-shell">
      <header className="editor-header">
        <span className="editor-title">Ledger</span>
        <span className="save-status" style={{ color: statusColor }}>
          {statusLabel}
        </span>
      </header>
      <main className="editor-main">
        <EditorContent editor={editor} className="editor-content" />
      </main>
    </div>
  );
}

.editor-shell {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

.editor-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0.75rem 1.5rem;
  background: #ffffff;
  border-bottom: 1px solid #e5e7eb;
  position: sticky;
  top: 0;
  z-index: 10;
}

.editor-title {
  font-size: 1rem;
  font-weight: 600;
  color: #1f2328;
  letter-spacing: 0.02em;
}

.save-status {
  font-size: 0.8rem;
  color: #57606a;
  transition: color 0.2s;
}

.editor-main {
  flex: 1;
  display: flex;
  justify-content: center;
  padding: 3rem 1.5rem;
}

.editor-content {
  width: 100%;
  max-width: 720px;
}

/* Tiptap ProseMirror wrapper */
.editor-content .ProseMirror {
  outline: none;
  font-size: 1.05rem;
  line-height: 1.75;
  color: #1f2328;
  caret-color: #3b82d4;
  min-height: 60vh;
}

.editor-content .ProseMirror p {
  margin: 0 0 1.2em 0;
}

.editor-content .ProseMirror p:last-child {
  margin-bottom: 0;
}

/* Subtle placeholder when empty */
.editor-content .ProseMirror.is-editor-empty::before {
  content: 'Start writing…';
  color: #adb5bd;
  pointer-events: none;
  float: left;
  height: 0;
}

